export function dysfunctionFactor(d: number | null | undefined): number {
  if (d == null || d <= 1) return 1.00;
  if (d <= 2) return 0.92;
  if (d <= 3) return 0.80;
  if (d <= 4) return 0.60;
  return 0.35;
}
